@namespace sv_da6d656e61974f38857de0a050205614.Components.Pages.JobApplication

<div class="work-entry">
    <div class="form-row">
        <div class="form-group">
            <label>Company Name *</label>
            <input type="text" value="@Entry.Company"
                   @onchange="e => Update(Entry with { Company = (string?)e.Value ?? string.Empty })" />
        </div>
        <div class="form-group">
            <label>Job Title *</label>
            <input type="text" value="@Entry.Title"
                   @onchange="e => Update(Entry with { Title = (string?)e.Value ?? string.Empty })" />
        </div>
    </div>
    <div class="form-row">
        <div class="form-group">
            <label>Start Date *</label>
            <input type="date" value="@Entry.StartDate.ToString("yyyy-MM-dd")"
                   @onchange="e => Update(Entry with { StartDate = DateTime.Parse((string?)e.Value ?? DateTime.Today.ToString("yyyy-MM-dd")) })" />
        </div>
        <div class="form-group">
            <label>
                <input type="checkbox" checked="@IsCurrent"
                       @onchange="e => OnCurrentChanged((bool?)e.Value ?? false)" />
                Currently working here
            </label>
            @if (!IsCurrent)
            {
                <label>End Date</label>
                <input type="date" value="@(Entry.EndDate?.ToString("yyyy-MM-dd") ?? string.Empty)"
                       @onchange="e => Update(Entry with { EndDate = string.IsNullOrEmpty((string?)e.Value) ? null : DateTime.Parse((string)e.Value) })" />
            }
        </div>
    </div>
    <div class="form-group">
        <label>Description</label>
        <textarea rows="3" value="@Entry.Description"
                  @onchange="e => Update(Entry with { Description = (string?)e.Value ?? string.Empty })"></textarea>
    </div>
    @if (CanRemove)
    {
        <button type="button" class="btn-remove" @onclick="OnRemove">Remove</button>
    }
</div>

@code {
    [Parameter, EditorRequired] public WorkEntryModel Entry { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<WorkEntryModel> OnEntryChanged { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate is null && Entry.IsCurrentJob;

    private void Update(WorkEntryModel updated) => OnEntryChanged.InvokeAsync(updated);

    private void OnCurrentChanged(bool isCurrent)
    {
        var updated = Entry with { IsCurrentJob = isCurrent, EndDate = isCurrent ? null : Entry.EndDate };
        OnEntryChanged.InvokeAsync(updated);
    }
}

