namespace sv_da6d656e61974f38857de0a050205614.Components.Pages.JobApplication;

/// <summary>
/// Mutable view models used by the multi-step form. Converted to immutable records on submission.
/// </summary>
public record PersonalInfoModel
{
    public string FullName { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
    public string Address { get; set; } = string.Empty;
}

public record WorkEntryModel
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public DateTime StartDate { get; set; } = DateTime.Today;
    public DateTime? EndDate { get; set; }
    public bool IsCurrentJob { get; set; }
    public string Description { get; set; } = string.Empty;
}

public record ReferenceModel
{
    public string Name { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
}

@namespace sv_da6d656e61974f38857de0a050205614.Components.Pages.JobApplication

<div class="step-content">
    <h3>Personal Information</h3>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message">@ErrorMessage</div>
    }

    <div class="form-group">
        <label>Full Name *</label>
        <input type="text" value="@Model.FullName"
               @onchange="e => Model = Model with { FullName = (string?)e.Value ?? string.Empty }" />
    </div>
    <div class="form-group">
        <label>Email *</label>
        <input type="email" value="@Model.Email"
               @onchange="e => Model = Model with { Email = (string?)e.Value ?? string.Empty }" />
    </div>
    <div class="form-group">
        <label>Phone *</label>
        <input type="text" value="@Model.Phone"
               @onchange="e => Model = Model with { Phone = (string?)e.Value ?? string.Empty }" />
    </div>
    <div class="form-group">
        <label>Address *</label>
        <input type="text" value="@Model.Address"
               @onchange="e => Model = Model with { Address = (string?)e.Value ?? string.Empty }" />
    </div>

    <div class="step-buttons">
        <button type="button" class="btn-next" @onclick="HandleNext" disabled="@IsValidating">
            @(IsValidating ? "Validating..." : "Next")
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<PersonalInfoModel> ModelChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<PersonalInfoModel> OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            ErrorMessage = "All fields are required.";
            return;
        }

        IsValidating = true;
        try
        {
            var isValidEmail = await ValidateEmail(Model.Email);
            if (!isValidEmail)
            {
                ErrorMessage = "The email address is not valid.";
                return;
            }
        }
        finally
        {
            IsValidating = false;
        }

        await ModelChanged.InvokeAsync(Model);
        await OnNext.InvokeAsync(Model);
    }
}

@namespace sv_da6d656e61974f38857de0a050205614.Components.Pages.JobApplication

<div class="step-content">
    <h3>Work History</h3>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message">@ErrorMessage</div>
    }

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <div class="entry-wrapper">
            <h4>Position @(index + 1)</h4>
            <WorkEntryForm Entry="@Entries[index]"
                           OnEntryChanged="e => UpdateEntry(index, e)"
                           CanRemove="@(Entries.Count > 1)"
                           OnRemove="() => RemoveEntry(index)" />
        </div>
    }

    <button type="button" class="btn-add" @onclick="AddEntry">+ Add Another Position</button>

    <div class="step-buttons">
        <button type="button" class="btn-back" @onclick="OnBack">Back</button>
        <button type="button" class="btn-next" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<List<WorkEntryModel>> EntriesChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void UpdateEntry(int index, WorkEntryModel updated)
    {
        Entries[index] = updated;
        EntriesChanged.InvokeAsync(Entries);
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
        EntriesChanged.InvokeAsync(Entries);
    }

    private void RemoveEntry(int index)
    {
        Entries.RemoveAt(index);
        EntriesChanged.InvokeAsync(Entries);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;
        var first = Entries[0];
        if (string.IsNullOrWhiteSpace(first.Company) || string.IsNullOrWhiteSpace(first.Title))
        {
            ErrorMessage = "At least one work entry with company and title is required.";
            return;
        }
        await EntriesChanged.InvokeAsync(Entries);
        await OnNext.InvokeAsync();
    }
}

@namespace sv_da6d656e61974f38857de0a050205614.Components.Pages.JobApplication

<div class="step-content">
    <h3>References</h3>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message">@ErrorMessage</div>
    }

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <div class="entry-wrapper">
            <h4>Reference @(index + 1)</h4>
            <ReferenceForm Entry="@References[index]"
                           OnEntryChanged="e => UpdateReference(index, e)"
                           CanRemove="@(References.Count > 2)"
                           OnRemove="() => RemoveReference(index)" />
        </div>
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn-add" @onclick="AddReference">+ Add Reference</button>
    }

    <div class="step-buttons">
        <button type="button" class="btn-back" @onclick="OnBack">Back</button>
        <button type="button" class="btn-next" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<List<ReferenceModel>> ReferencesChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void UpdateReference(int index, ReferenceModel updated)
    {
        References[index] = updated;
        ReferencesChanged.InvokeAsync(References);
    }

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
            ReferencesChanged.InvokeAsync(References);
        }
    }

    private void RemoveReference(int index)
    {
        References.RemoveAt(index);
        ReferencesChanged.InvokeAsync(References);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;
        var first = References[0];
        if (string.IsNullOrWhiteSpace(first.Name) || string.IsNullOrWhiteSpace(first.Email))
        {
            ErrorMessage = "At least one reference with name and email is required.";
            return;
        }
        await ReferencesChanged.InvokeAsync(References);
        await OnNext.InvokeAsync();
    }
}

@namespace sv_da6d656e61974f38857de0a050205614.Components.Pages.JobApplication

<div class="step-content">
    <h3>Cover Letter</h3>

    <div class="form-group">
        <label>Write your cover letter</label>
        <textarea rows="12" maxlength="2000" value="@CoverLetter"
                  @oninput="e => UpdateCoverLetter((string?)e.Value ?? string.Empty)"></textarea>
        <span class="char-count">@CoverLetter.Length / 2000 characters</span>
    </div>

    <div class="step-buttons">
        <button type="button" class="btn-back" @onclick="OnBack">Back</button>
        <button type="button" class="btn-next" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = string.Empty;
    [Parameter, EditorRequired] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private void UpdateCoverLetter(string value)
    {
        CoverLetter = value;
        CoverLetterChanged.InvokeAsync(value);
    }

    private async Task HandleNext()
    {
        await CoverLetterChanged.InvokeAsync(CoverLetter);
        await OnNext.InvokeAsync();
    }
}

@namespace sv_da6d656e61974f38857de0a050205614.Components.Pages.JobApplication

<div class="step-content">
    <h3>Review & Submit</h3>

    @if (IsSubmitted)
    {
        <div class="confirmation">
            <h4>✓ Application Submitted Successfully!</h4>
            <p>Your application ID is: <strong>@ApplicationId</strong></p>
        </div>
    }
    else
    {
        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="error-message">@ErrorMessage</div>
        }

        <section class="review-section">
            <div class="review-header">
                <h4>Personal Information</h4>
                <button type="button" class="btn-edit" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
            </div>
            <dl>
                <dt>Name</dt><dd>@Personal.FullName</dd>
                <dt>Email</dt><dd>@Personal.Email</dd>
                <dt>Phone</dt><dd>@Personal.Phone</dd>
                <dt>Address</dt><dd>@Personal.Address</dd>
            </dl>
        </section>

        <section class="review-section">
            <div class="review-header">
                <h4>Work History</h4>
                <button type="button" class="btn-edit" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="review-item">
                    <strong>@entry.Title</strong> at @entry.Company
                    <br />
                    <span>@entry.StartDate.ToString("MMM yyyy") – @(entry.IsCurrentJob ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")</span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p>@entry.Description</p>
                    }
                </div>
            }
        </section>

        <section class="review-section">
            <div class="review-header">
                <h4>References</h4>
                <button type="button" class="btn-edit" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
            </div>
            @foreach (var r in References)
            {
                <div class="review-item">
                    <strong>@r.Name</strong> (@r.Relationship)
                    <br />@r.Email | @r.Phone
                </div>
            }
        </section>

        <section class="review-section">
            <div class="review-header">
                <h4>Cover Letter</h4>
                <button type="button" class="btn-edit" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
            </div>
            <p class="cover-letter-preview">@CoverLetter</p>
        </section>

        <div class="step-buttons">
            <button type="button" class="btn-back" @onclick="OnBack">Back</button>
            <button type="button" class="btn-submit" @onclick="HandleSubmit" disabled="@IsSubmitting">
                @(IsSubmitting ? "Submitting..." : "Submit Application")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = string.Empty;
    [Parameter, EditorRequired] public EventCallback<int> OnEditStep { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
