@namespace sv_da6d656e61974f38857de0a050205614.Components.Pages.JobApplication

<div class="step-content">
    <h3>Personal Information</h3>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message">@ErrorMessage</div>
    }

    <div class="form-group">
        <label>Full Name *</label>
        <input type="text" value="@Model.FullName"
               @onchange="e => Model = Model with { FullName = (string?)e.Value ?? string.Empty }" />
    </div>
    <div class="form-group">
        <label>Email *</label>
        <input type="email" value="@Model.Email"
               @onchange="e => Model = Model with { Email = (string?)e.Value ?? string.Empty }" />
    </div>
    <div class="form-group">
        <label>Phone *</label>
        <input type="text" value="@Model.Phone"
               @onchange="e => Model = Model with { Phone = (string?)e.Value ?? string.Empty }" />
    </div>
    <div class="form-group">
        <label>Address *</label>
        <input type="text" value="@Model.Address"
               @onchange="e => Model = Model with { Address = (string?)e.Value ?? string.Empty }" />
    </div>

    <div class="step-buttons">
        <button type="button" class="btn-next" @onclick="HandleNext" disabled="@IsValidating">
            @(IsValidating ? "Validating..." : "Next")
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<PersonalInfoModel> ModelChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<PersonalInfoModel> OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            ErrorMessage = "All fields are required.";
            return;
        }

        IsValidating = true;
        try
        {
            var isValidEmail = await ValidateEmail(Model.Email);
            if (!isValidEmail)
            {
                ErrorMessage = "The email address is not valid.";
                return;
            }
        }
        finally
        {
            IsValidating = false;
        }

        await ModelChanged.InvokeAsync(Model);
        await OnNext.InvokeAsync(Model);
    }
}

