@page "/apply"
@using sv_da6d656e61974f38857de0a050205614.Models
@using sv_da6d656e61974f38857de0a050205614.Components.Pages.JobApplication
@rendermode InteractiveServer

@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="job-application">
    <h2>Job Application</h2>

    <StepIndicator CurrentStep="@currentStep"
                   CompletedSteps="@completedSteps"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="@personalInfo"
                              ModelChanged="m => personalInfo = m"
                              OnNext="HandlePersonalNext"
                              ValidateEmail="ApplicationService.ValidateEmailAsync" />
            break;
        case 1:
            <WorkHistoryStep Entries="@workEntries"
                             EntriesChanged="e => workEntries = e"
                             OnNext="() => AdvanceStep()"
                             OnBack="() => GoToStep(0)" />
            break;
        case 2:
            <ReferencesStep References="@references"
                            ReferencesChanged="r => references = r"
                            OnNext="() => AdvanceStep()"
                            OnBack="() => GoToStep(1)" />
            break;
        case 3:
            <CoverLetterStep CoverLetter="@coverLetter"
                             CoverLetterChanged="c => coverLetter = c"
                             OnNext="() => AdvanceStep()"
                             OnBack="() => GoToStep(2)" />
            break;
        case 4:
            <ReviewStep Personal="@personalInfo"
                        WorkEntries="@workEntries"
                        References="@references"
                        CoverLetter="@coverLetter"
                        OnEditStep="GoToStep"
                        OnBack="() => GoToStep(3)"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int currentStep;
    private HashSet<int> completedSteps = new();

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = string.Empty;

    private Task HandlePersonalNext(PersonalInfoModel model)
    {
        personalInfo = model;
        AdvanceStep();
        return Task.CompletedTask;
    }

    private void AdvanceStep()
    {
        completedSteps.Add(currentStep);
        currentStep++;
    }

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private async Task<int> SubmitApplication()
    {
        var application = new JobApplication(
            new PersonalInfo(personalInfo.FullName, personalInfo.Email, personalInfo.Phone, personalInfo.Address),
            new WorkHistory(workEntries.Select(e => new WorkEntry(
                e.Company, e.Title, e.StartDate, e.IsCurrentJob ? null : e.EndDate, e.Description)).ToList()),
            references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
            coverLetter
        );

        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

.job-application {
    max-width: 800px;
    margin: 0 auto;
    padding: 2rem;
}

/* Step Indicator */
.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 2rem;
    flex-wrap: wrap;
    gap: 0.25rem;
}

.step-indicator .step {
    display: flex;
    flex-direction: column;
    align-items: center;
    background: none;
    border: none;
    cursor: default;
    padding: 0.5rem;
    min-width: 80px;
}

.step-indicator .step:not(:disabled) {
    cursor: pointer;
}

.step-indicator .step .step-number {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.85rem;
    margin-bottom: 0.25rem;
    border: 2px solid #ccc;
    color: #999;
    background: #f9f9f9;
}

.step-indicator .step.active .step-number {
    border-color: #0d6efd;
    background: #0d6efd;
    color: white;
}

.step-indicator .step.completed .step-number {
    border-color: #198754;
    background: #198754;
    color: white;
}

.step-indicator .step .step-label {
    font-size: 0.75rem;
    color: #999;
    text-align: center;
}

.step-indicator .step.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-indicator .step.completed .step-label {
    color: #198754;
}

.step-connector {
    width: 30px;
    height: 2px;
    background: #ccc;
    margin: 0 0.25rem;
    align-self: center;
    margin-bottom: 1rem;
}

/* Form Elements */
.step-content {
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 1.5rem;
}

.step-content h3 {
    margin-top: 0;
    margin-bottom: 1.5rem;
    color: #333;
}

.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.25rem;
    font-weight: 500;
    color: #555;
}

.form-group input[type="text"],
.form-group input[type="email"],
.form-group input[type="date"],
.form-group textarea {
    width: 100%;
    padding: 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 1rem;
    box-sizing: border-box;
}

.form-group textarea {
    resize: vertical;
}

.form-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 1rem;
}

/* Buttons */
.step-buttons {
    display: flex;
    justify-content: space-between;
    margin-top: 1.5rem;
    padding-top: 1rem;
    border-top: 1px solid #eee;
}

.btn-next, .btn-submit {
    background: #0d6efd;
    color: white;
    border: none;
    padding: 0.6rem 1.5rem;
    border-radius: 4px;
    font-size: 1rem;
    cursor: pointer;
    margin-left: auto;
}

.btn-next:hover, .btn-submit:hover {
    background: #0b5ed7;
}

.btn-next:disabled, .btn-submit:disabled {
    background: #6c757d;
    cursor: not-allowed;
}

.btn-back {
    background: #6c757d;
    color: white;
    border: none;
    padding: 0.6rem 1.5rem;
    border-radius: 4px;
    font-size: 1rem;
    cursor: pointer;
}

.btn-back:hover {
    background: #5a6268;
}

.btn-add {
    background: none;
    border: 1px dashed #0d6efd;
    color: #0d6efd;
    padding: 0.5rem 1rem;
    border-radius: 4px;
    cursor: pointer;
    margin-top: 0.5rem;
}

.btn-add:hover {
    background: #f0f7ff;
}

.btn-remove {
    background: none;
    border: none;
    color: #dc3545;
    cursor: pointer;
    font-size: 0.85rem;
    padding: 0.25rem 0;
}

.btn-remove:hover {
    text-decoration: underline;
}

.btn-edit {
    background: none;
    border: none;
    color: #0d6efd;
    cursor: pointer;
    font-size: 0.85rem;
}

.btn-edit:hover {
    text-decoration: underline;
}

/* Entry Wrappers */
.entry-wrapper {
    border: 1px solid #eee;
    border-radius: 6px;
    padding: 1rem;
    margin-bottom: 1rem;
    background: #fafafa;
}

.entry-wrapper h4 {
    margin-top: 0;
    margin-bottom: 0.75rem;
    color: #666;
    font-size: 0.9rem;
}

/* Character Count */
.char-count {
    display: block;
    text-align: right;
    font-size: 0.85rem;
    color: #666;
    margin-top: 0.25rem;
}

/* Error Messages */
.error-message {
    background: #f8d7da;
    border: 1px solid #f5c6cb;
    color: #721c24;
    padding: 0.75rem;
    border-radius: 4px;
    margin-bottom: 1rem;
}

/* Review Step */
.review-section {
    margin-bottom: 1.5rem;
    padding-bottom: 1rem;
    border-bottom: 1px solid #eee;
}

.review-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.review-header h4 {
    margin: 0 0 0.5rem 0;
}

.review-section dl {
    display: grid;
    grid-template-columns: 120px 1fr;
    gap: 0.25rem 1rem;
    margin: 0;
}

.review-section dt {
    font-weight: 500;
    color: #666;
}

.review-section dd {
    margin: 0;
}

.review-item {
    margin-bottom: 0.75rem;
    padding: 0.5rem;
    background: #f9f9f9;
    border-radius: 4px;
}

.cover-letter-preview {
    white-space: pre-wrap;
    background: #f9f9f9;
    padding: 1rem;
    border-radius: 4px;
}

/* Confirmation */
.confirmation {
    text-align: center;
    padding: 2rem;
}

.confirmation h4 {
    color: #198754;
    font-size: 1.5rem;
}

