@page "/apply"
@using sv_da6d656e61974f38857de0a050205614.Models
@using sv_da6d656e61974f38857de0a050205614.Components.Pages.JobApplication
@rendermode InteractiveServer

@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="job-application">
    <h2>Job Application</h2>

    <StepIndicator CurrentStep="@currentStep"
                   CompletedSteps="@completedSteps"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="@personalInfo"
                              ModelChanged="m => personalInfo = m"
                              OnNext="HandlePersonalNext"
                              ValidateEmail="ApplicationService.ValidateEmailAsync" />
            break;
        case 1:
            <WorkHistoryStep Entries="@workEntries"
                             EntriesChanged="e => workEntries = e"
                             OnNext="() => AdvanceStep()"
                             OnBack="() => GoToStep(0)" />
            break;
        case 2:
            <ReferencesStep References="@references"
                            ReferencesChanged="r => references = r"
                            OnNext="() => AdvanceStep()"
                            OnBack="() => GoToStep(1)" />
            break;
        case 3:
            <CoverLetterStep CoverLetter="@coverLetter"
                             CoverLetterChanged="c => coverLetter = c"
                             OnNext="() => AdvanceStep()"
                             OnBack="() => GoToStep(2)" />
            break;
        case 4:
            <ReviewStep Personal="@personalInfo"
                        WorkEntries="@workEntries"
                        References="@references"
                        CoverLetter="@coverLetter"
                        OnEditStep="GoToStep"
                        OnBack="() => GoToStep(3)"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int currentStep;
    private HashSet<int> completedSteps = new();

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = string.Empty;

    private Task HandlePersonalNext(PersonalInfoModel model)
    {
        personalInfo = model;
        AdvanceStep();
        return Task.CompletedTask;
    }

    private void AdvanceStep()
    {
        completedSteps.Add(currentStep);
        currentStep++;
    }

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private async Task<int> SubmitApplication()
    {
        var application = new JobApplication(
            new PersonalInfo(personalInfo.FullName, personalInfo.Email, personalInfo.Phone, personalInfo.Address),
            new WorkHistory(workEntries.Select(e => new WorkEntry(
                e.Company, e.Title, e.StartDate, e.IsCurrentJob ? null : e.EndDate, e.Description)).ToList()),
            references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
            coverLetter
        );

        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

