private void Update(WorkEntryModel updated) => OnEntryChanged.InvokeAsync(updated);

private void OnStartDateChanged(ChangeEventArgs e)
{
    var val = (string?)e.Value;
    var date = string.IsNullOrEmpty(val) ? DateTime.Today : DateTime.Parse(val);
    Update(Entry with { StartDate = date });
}

private void OnEndDateChanged(ChangeEventArgs e)
{
    var val = (string?)e.Value;
    var date = string.IsNullOrEmpty(val) ? (DateTime?)null : DateTime.Parse(val);
    Update(Entry with { EndDate = date });
}

private void OnCurrentChanged(bool isCurrent)
{
    var updated = Entry with { IsCurrentJob = isCurrent, EndDate = isCurrent ? null : Entry.EndDate };
    OnEntryChanged.InvokeAsync(updated);
}

